package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.net.URL;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserParseTest {

    private URL mockUrl;
    private InputStream mockInputStream;

    @BeforeEach
    void setup() throws IOException {
        mockUrl = mock(URL.class);
        mockInputStream = mock(InputStream.class);

        when(mockUrl.openStream()).thenReturn(mockInputStream);
    }

    @Test
    void testParse_withValidArguments_shouldReturnCSVParser() throws IOException {
        Charset charset = Charset.forName("UTF-8");
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            // Assertions.notNull calls should pass without exceptions
            mockedAssertions.when(() -> Assertions.notNull(any(), any())).thenAnswer(invocation -> null);

            CSVParser parser = CSVParser.parse(mockUrl, charset, format);

            assertNotNull(parser);
            assertEquals(format, getField(parser, "format"));
            assertFalse((Boolean) getField(parser, "headerMap") == null);
        }
    }

    @Test
    void testParse_nullUrl_shouldThrowException() {
        Charset charset = Charset.forName("UTF-8");
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            mockedAssertions.when(() -> Assertions.notNull(null, "url"))
                    .thenThrow(new NullPointerException("url"));

            NullPointerException exception = assertThrows(NullPointerException.class, () -> {
                CSVParser.parse(null, charset, format);
            });
            assertEquals("url", exception.getMessage());
        }
    }

    @Test
    void testParse_nullCharset_shouldUseUTF8Charset() throws IOException {
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class);
             MockedStatic<Charset> mockedCharset = Mockito.mockStatic(Charset.class)) {

            mockedAssertions.when(() -> Assertions.notNull(any(), any())).thenAnswer(invocation -> null);
            mockedCharset.when(() -> Charset.forName("UTF-8")).thenReturn(Charset.forName("UTF-8"));

            CSVParser parser = CSVParser.parse(mockUrl, null, format);

            assertNotNull(parser);
            assertEquals(format, getField(parser, "format"));
        }
    }

    @Test
    void testParse_nullFormat_shouldThrowException() {
        Charset charset = Charset.forName("UTF-8");

        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            mockedAssertions.when(() -> Assertions.notNull(null, "format"))
                    .thenThrow(new NullPointerException("format"));

            NullPointerException exception = assertThrows(NullPointerException.class, () -> {
                CSVParser.parse(mockUrl, charset, null);
            });
            assertEquals("format", exception.getMessage());
        }
    }

    private Object getField(Object obj, String fieldName) {
        try {
            java.lang.reflect.Field field = CSVParser.class.getDeclaredField(fieldName);
            field.setAccessible(true);
            return field.get(obj);
        } catch (Exception e) {
            fail("Reflection error: " + e.getMessage());
            return null;
        }
    }
}
